import React, { useState, useEffect } from 'react';
import SensorForm from './components/SensorForm';
import PredictionResult from './components/PredictionResult';
import AlertPanel from './components/AlertPanel';
import MaintenanceReport from './components/MaintenanceReport';
import { getAlerts, acknowledgeAlert, resolveAlert, generateReport, getMachines } from './services/api';
import './App.css';

function App() {
  const [predictionResult, setPredictionResult] = useState(null);
  const [alerts, setAlerts] = useState([]);
  const [machines, setMachines] = useState([]);
  const [selectedMachine, setSelectedMachine] = useState(null);
  const [report, setReport] = useState(null);
  const [loadingReport, setLoadingReport] = useState(false);
  const [tab, setTab] = useState('monitor'); // 'monitor', 'alerts', 'report'

  // Load machines on mount
  useEffect(() => {
    loadMachines();
    loadAlerts();
  }, []);

  const loadMachines = async () => {
    try {
      const data = await getMachines();
      setMachines(data);
    } catch (error) {
      console.error('Error loading machines:', error);
    }
  };

  const loadAlerts = async () => {
    try {
      const data = await getAlerts('OPEN');
      setAlerts(data);
    } catch (error) {
      console.error('Error loading alerts:', error);
    }
  };

  const handleSensorSubmit = (result) => {
    setPredictionResult(result);
    // Reload alerts after new reading
    loadAlerts();
  };

  const handleAcknowledgeAlert = async (alertId) => {
    try {
      await acknowledgeAlert(alertId);
      loadAlerts();
    } catch (error) {
      alert('Error acknowledging alert: ' + error.message);
    }
  };

  const handleResolveAlert = async (alertId) => {
    try {
      await resolveAlert(alertId);
      loadAlerts();
    } catch (error) {
      alert('Error resolving alert: ' + error.message);
    }
  };

  const handleGenerateReport = async () => {
    if (!selectedMachine) {
      alert('Please select a machine');
      return;
    }

    setLoadingReport(true);
    try {
      const data = await generateReport(selectedMachine, 7);
      setReport(data);
      setTab('report');
    } catch (error) {
      alert('Error generating report: ' + error.message);
    } finally {
      setLoadingReport(false);
    }
  };

  return (
    <div className="app-container">
      <header className="app-header">
        <h1>🏭 Refinery Predictive Maintenance System</h1>
        <p>AI-Powered Machine Health Monitoring</p>
      </header>

      <div className="app-content">
        <div className="tabs">
          <button
            className={`tab-btn ${tab === 'monitor' ? 'active' : ''}`}
            onClick={() => setTab('monitor')}
          >
            📊 Monitor
          </button>
          <button
            className={`tab-btn ${tab === 'alerts' ? 'active' : ''}`}
            onClick={() => setTab('alerts')}
          >
            🚨 Alerts {alerts.length > 0 && `(${alerts.length})`}
          </button>
          <button
            className={`tab-btn ${tab === 'report' ? 'active' : ''}`}
            onClick={() => setTab('report')}
          >
            📈 Report
          </button>
        </div>

        {/* Monitor Tab */}
        {tab === 'monitor' && (
          <div className="tab-content">
            <SensorForm onSubmit={handleSensorSubmit} />
            {predictionResult && <PredictionResult result={predictionResult} />}
          </div>
        )}

        {/* Alerts Tab */}
        {tab === 'alerts' && (
          <div className="tab-content">
            <AlertPanel
              alerts={alerts}
              onAcknowledge={handleAcknowledgeAlert}
              onResolve={handleResolveAlert}
            />
          </div>
        )}

        {/* Report Tab */}
        {tab === 'report' && (
          <div className="tab-content">
            <div className="report-generator">
              <h3>Generate Maintenance Report</h3>
              <div className="report-controls">
                <select
                  value={selectedMachine || ''}
                  onChange={(e) => setSelectedMachine(e.target.value)}
                  className="machine-select"
                >
                  <option value="">Select a machine...</option>
                  {machines.map(machine => (
                    <option key={machine.id} value={machine.machine_id}>
                      {machine.machine_id} - {machine.name}
                    </option>
                  ))}
                </select>
                <button
                  className="generate-btn"
                  onClick={handleGenerateReport}
                  disabled={loadingReport || !selectedMachine}
                >
                  {loadingReport ? 'Generating...' : 'Generate Report'}
                </button>
              </div>
              {report && <MaintenanceReport report={report} />}
            </div>
          </div>
        )}
      </div>

      <footer className="app-footer">
        <p>Powered by Django REST Framework + Random Forest ML</p>
      </footer>
    </div>
  );
}

export default App;
